func adminPercent(part, total int) int {
	if total <= 0 {
		return 0
	}
	p := part * 100 / total
	if p > 100 {
		return 100
	}
	return p
}

func adminTime(t time.Time) string {
	if t.IsZero() {
		return "Never"
	}
	return t.Local().Format("Jan 2, 3:04 PM")
}

func adminMailPendingAge(t time.Time) string {
	if t.IsZero() {
		return "None"
	}
	age := time.Since(t)
	if age < 0 {
		return "in the future"
	}
	if age < time.Minute {
		return "just now"
	}
	if age < time.Hour {
		return fmt.Sprintf("%dm ago", int(age/time.Minute))
	}
	if age < 24*time.Hour {
		return fmt.Sprintf("%dh ago", int(age/time.Hour))
	}
	return fmt.Sprintf("%dd ago", int(age/(24*time.Hour)))
}

func adminSMTPProfileDuration(milliseconds int64) string {
	if milliseconds <= 0 {
		return "—"
	}
	if milliseconds < 1000 {
		return fmt.Sprintf("%d ms", milliseconds)
	}
	return fmt.Sprintf("%.1f s", float64(milliseconds)/1000)
}

func adminChecked(total, pending int) int {
	checked := total - pending
	if checked < 0 {
		return 0
	}
	return checked
}

func adminLatestAvatarError(status models.AvatarStatus) string {
	for _, attempt := range status.RecentErrors {
		if attempt.Message != "" {
			return attempt.Message
		}
	}
	return adminError(status.Backfill.LastError)
}

func adminPanelTitleClass() string {
	return "text-sm font-semibold uppercase tracking-wider text-muted-foreground"
}

