func adminContactEventLabel(eventType string) string {
	switch eventType {
	case "backfill_forced":
		return "Backfill requested"
	case "backfill_started":
		return "Backfill started"
	case "backfill_completed":
		return "Backfill completed"
	case "manual_contact_added":
		return "Manual contact added"
	case "observed_contact_added":
		return "Observed contact added"
	case "contact_deleted":
		return "Contact deleted"
	case "observed_contacts_deleted":
		return "Discovered contacts deleted"
	default:
		return strings.Title(strings.ReplaceAll(eventType, "_", " "))
	}
}

func adminContactEventClass(eventType string) string {
	switch eventType {
	case "backfill_forced", "backfill_started":
		return "bg-amber-500/12 text-amber-700 dark:text-amber-300"
	case "backfill_completed", "manual_contact_added", "observed_contact_added":
		return "bg-emerald-500/12 text-emerald-700 dark:text-emerald-300"
	case "contact_deleted", "observed_contacts_deleted":
		return "bg-red-500/12 text-red-700 dark:text-red-300"
	default:
		return "bg-muted text-muted-foreground"
	}
}

func adminContactRunDescription(state models.ContactBackfillState) string {
	if state.InProgress {
		return "Manual observed-contact backfill is scanning stored messages and creating missing discovered contacts."
	}
	if state.LastError != "" {
		return "Last backfill failed. Review the event log and server logs before retrying."
	}
	return "Backfill scans stored messages for senders and recipients that are not already represented as contacts."
}

func adminContactRunLabel(state models.ContactBackfillState) string {
	if state.InProgress {
		return "Backfilling"
	}
	if state.LastError != "" {
		return "Error"
	}
	return "Idle"
}

func adminContactSyncProviderLabel(provider string) string {
	switch strings.ToLower(strings.TrimSpace(provider)) {
	case "gmail":
		return "Gmail"
	case "outlook":
		return "Outlook"
	case "carddav":
		return "CardDAV"
	case "":
		return "Unknown"
	default:
		return strings.Title(strings.ReplaceAll(provider, "_", " "))
	}
}

func adminContactSyncLabel(sync models.ContactSyncStatus) string {
	if sync.Running {
		return "Syncing"
	}
	if sync.LastError != "" {
		return "Error"
	}
	if sync.Enabled {
		return "Enabled"
	}
	if sync.Capable {
		return "Configured"
	}
	return "Disabled"
}

func adminContactSyncClass(sync models.ContactSyncStatus) string {
	if sync.Running {
		return "bg-amber-500/12 text-amber-700 dark:text-amber-300"
	}
	if sync.LastError != "" {
		return "bg-red-500/12 text-red-700 dark:text-red-300"
	}
	if sync.Enabled {
		return "bg-emerald-500/12 text-emerald-700 dark:text-emerald-300"
	}
	return "bg-muted text-muted-foreground"
}

func adminLabelProviderLabel(provider string) string {
	switch strings.ToLower(strings.TrimSpace(provider)) {
	case "gmail":
		return "Gmail labels"
	case "outlook":
		return "Outlook categories"
	case "imap_keyword":
		return "IMAP keywords"
	case "local":
		return "Local labels"
	case "":
		return "Unknown"
	default:
		return strings.Title(strings.ReplaceAll(provider, "_", " "))
	}
}

func adminLabelSyncLabel(account models.LabelAccountSyncStatus) string {
	if account.Sync.LastError != "" {
		return "Error"
	}
	if !account.Sync.LastRunFinishedAt.IsZero() {
		return "Synced"
	}
	return "Waiting"
}

func adminLabelSyncClass(account models.LabelAccountSyncStatus) string {
	if account.Sync.LastError != "" || account.MutationErrors > 0 {
		return "bg-red-500/12 text-red-700 dark:text-red-300"
	}
	if account.PendingMutations > 0 {
		return "bg-amber-500/12 text-amber-700 dark:text-amber-300"
	}
	if !account.Sync.LastRunFinishedAt.IsZero() {
		return "bg-emerald-500/12 text-emerald-700 dark:text-emerald-300"
	}
	return "bg-muted text-muted-foreground"
}

func adminLabelCoverageText(withLabels int, total int) string {
	return fmt.Sprintf("%d%%", adminPercent(withLabels, total))
}

func adminOutlookGraphParityStatus(status *models.OutlookGraphDiagnostics) string {
	if status != nil && status.GraphParityReady {
		return "Ready"
	}
	return "Needs repair"
}

func adminGmailAPIParityStatus(status *models.GmailAPIDiagnostics) string {
	if status != nil && status.APIParityReady {
		return "Ready"
	}
	return "Needs repair"
}

