func adminMailHealthStateLabel(state string) string {
	switch state {
	case "pending":
		return "Pending"
	case "processing", "syncing", "copying", "sending":
		return "In progress"
	case "failed":
		return "Failed"
	case "ambiguous":
		return "Needs review"
	case "applied":
		return "Applied"
	default:
		return state
	}
}

func adminMailHealthKindLabel(kind string) string {
	switch kind {
	case "read":
		return "Read state"
	case "starred":
		return "Starred state"
	case "move":
		return "Move"
	case "delete":
		return "Delete"
	default:
		return kind
	}
}

